import{_ as i,C as s,o as t,c as n,a2 as a,b as d,w as r,a as l,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const w=JSON.parse('{"title":"Warfare Domain","description":"","frontmatter":{},"headers":[],"relativePath":"warfare/overview.md","filePath":"warfare/overview.md","lastUpdated":null}'),m={name:"warfare/overview.md"};function f(p,e,u,b,v,y){const o=s("Mermaid");return t(),n("div",null,[e[1]||(e[1]=a('<h1 id="warfare-domain" tabindex="-1">Warfare Domain <a class="header-anchor" href="#warfare-domain" aria-label="Permalink to &quot;Warfare Domain&quot;">​</a></h1><p>The Warfare domain plugin is the first and reference domain plugin for DINOForge. It extends the platform with combat-oriented modding: factions, doctrines, unit taxonomies, weapon systems, wave composition, and themed content packs.</p><h2 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h2><p>DINO is a medieval siege defense RTS where you defend against massive hordes (25,000+ enemies). The Warfare domain reimagines these battles with themed factions — modern military, Star Wars Clone Wars, and more.</p><p>The key insight: every battle is the same mechanical structure (line infantry, anti-armor, artillery, defenses, waves), just skinned differently. DINOForge makes that skin-swap declarative.</p><h2 id="three-faction-archetypes" tabindex="-1">Three Faction Archetypes <a class="header-anchor" href="#three-faction-archetypes" aria-label="Permalink to &quot;Three Faction Archetypes&quot;">​</a></h2><p>All factions map to one of three mechanical families:</p>',7)),(t(),d(h,null,{default:r(()=>[c(o,{id:"mermaid-21",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20O%5BOrder%3Cbr%2F%3EQuality%20Army%5D%20---%20IS%5BIndustrial%20Swarm%3Cbr%2F%3EAttrition%20Army%5D%0A%20%20%20%20IS%20---%20A%5BAsymmetric%3Cbr%2F%3EInsurgent%20Army%5D%0A%0A%20%20%20%20style%20O%20fill%3A%230f3460%2Cstroke%3A%23fff%2Ccolor%3A%23fff%0A%20%20%20%20style%20IS%20fill%3A%23533483%2Cstroke%3A%23fff%2Ccolor%3A%23fff%0A%20%20%20%20style%20A%20fill%3A%23e94560%2Cstroke%3A%23fff%2Ccolor%3A%23fff%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<table tabindex="0"><thead><tr><th>Archetype</th><th>Traits</th><th>Factions</th></tr></thead><tbody><tr><td><strong>Order</strong></td><td>Strong line infantry, reliable DPS, better defenses, higher unit cost</td><td>Republic, West</td></tr><tr><td><strong>Industrial Swarm</strong></td><td>Larger numbers, cheaper core, expendable, strong siege</td><td>CIS, Classic West Enemy</td></tr><tr><td><strong>Asymmetric</strong></td><td>Light units, mobility, ambush, raid pressure</td><td>Guerrilla West Enemy</td></tr></tbody></table><h2 id="theme-packs" tabindex="-1">Theme Packs <a class="header-anchor" href="#theme-packs" aria-label="Permalink to &quot;Theme Packs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pack</th><th>Factions</th><th>Theme</th></tr></thead><tbody><tr><td>Republic vs CIS</td><td>Galactic Republic, CIS</td><td>Star Wars Clone Wars</td></tr><tr><td>West vs Enemies</td><td>West, Classic West Enemy, Guerrilla West Enemy</td><td>Modern Warfare</td></tr></tbody></table><h2 id="implementation-order" tabindex="-1">Implementation Order <a class="header-anchor" href="#implementation-order" aria-label="Permalink to &quot;Implementation Order&quot;">​</a></h2><ol><li><strong>West vs Classic West Enemy</strong> — Easiest, proves the framework works</li><li><strong>Republic vs CIS</strong> — Harder art/audio, proves theme-skin abstraction</li><li><strong>West vs Guerrilla Enemy</strong> — Asymmetry, hardest balance challenge</li></ol><h2 id="content-production-strategy" tabindex="-1">Content Production Strategy <a class="header-anchor" href="#content-production-strategy" aria-label="Permalink to &quot;Content Production Strategy&quot;">​</a></h2><h3 id="level-1-—-zero-new-model-build-mvp" tabindex="-1">Level 1 — Zero-New-Model Build (MVP) <a class="header-anchor" href="#level-1-—-zero-new-model-build-mvp" aria-label="Permalink to &quot;Level 1 — Zero-New-Model Build (MVP)&quot;">​</a></h3><p>Only: renamed units, new icons, recolors, projectile/VFX swaps, stat changes, wave logic, SFX swaps, text/UI replacement. Gets a playable framework fast.</p><h3 id="level-2-—-selective-model-swaps" tabindex="-1">Level 2 — Selective Model Swaps <a class="header-anchor" href="#level-2-—-selective-model-swaps" aria-label="Permalink to &quot;Level 2 — Selective Model Swaps&quot;">​</a></h3><p>Add: hero units, key vehicles, signature defenses, faction command buildings. Only highest-visibility pieces.</p><h3 id="level-3-—-full-asset-conversion" tabindex="-1">Level 3 — Full Asset Conversion <a class="header-anchor" href="#level-3-—-full-asset-conversion" aria-label="Permalink to &quot;Level 3 — Full Asset Conversion&quot;">​</a></h3><p>Only after the framework is proven fun. This is the difference between a released mod and a dead dream repo.</p><h2 id="module-split" tabindex="-1">Module Split <a class="header-anchor" href="#module-split" aria-label="Permalink to &quot;Module Split&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>DinoWarfare.Core</code></td><td>Schemas, faction definitions, balance tables, shared enums</td></tr><tr><td><code>DinoWarfare.ECS</code></td><td>Entity queries, ECS patching, component mutation, spawn overrides</td></tr><tr><td><code>DinoWarfare.Assets</code></td><td>Icon registry, localization, audio routing, VFX registry</td></tr><tr><td><code>DinoWarfare.Campaign</code></td><td>Wave composition, faction matchup rules, mission overrides</td></tr><tr><td><code>DinoWarfare.Theme.StarWars</code></td><td>Republic/CIS content pack</td></tr><tr><td><code>DinoWarfare.Theme.Modern</code></td><td>West/Classic Enemy/Guerrilla content pack</td></tr><tr><td><code>DinoWarfare.Debug</code></td><td>Overlay, inspector, hot reload, test-spawn menus</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/warfare/factions">Factions</a> — Detailed faction guide</li><li><a href="/warfare/unit-roles">Unit Roles</a> — The 13 required role slots</li><li><a href="/reference/schemas">Schema Reference</a> — Faction and unit schemas</li></ul>',16))])}const S=i(m,[["render",f]]);export{w as __pageData,S as default};
